async function main() {
  console.log("🏥 Sri Srinivasa Medicals — Database Seeder\n");

  const rootConn = await mysql.createConnection({
    host:     process.env.DB_HOST || "127.0.0.1",
    port:     parseInt(process.env.DB_PORT || "3306", 10),
    user:     process.env.DB_USER || "root",
    password: process.env.DB_PASSWORD || "",
    multipleStatements: true,
  });

  console.log("📋 Running schema.sql …");
  const schemaSql = fs.readFileSync(SCHEMA_PATH, "utf8");
  await rootConn.query(schemaSql);
  await rootConn.end();
  console.log("   ✅ Schema applied successfully.\n");

  const pool = require("./db");

  console.log("📂 Seeding categories …");
  for (const cat of CATEGORIES) {
    await pool.execute(
      `INSERT IGNORE INTO categories (slug, name, description, color, show_stock) VALUES (?, ?, ?, ?, ?)`,
      [cat.slug, cat.name, cat.description, cat.color, cat.show_stock]
    );
  }
  console.log(`   ✅ ${CATEGORIES.length} categories processed.\n`);

  console.log("💊 Seeding products (total: " + PRODUCTS.length + ") …");
  for (const prod of PRODUCTS) {
    await pool.execute(
      `INSERT IGNORE INTO products (id, sku, name, category_slug, description, manufacturer, price, mrp, stock_quantity, availability_status, image_url, image_source_type)
       VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
      [
        prod.id, prod.sku, prod.name, prod.category_slug, prod.description, prod.manufacturer,
        prod.price, prod.mrp, prod.stock_quantity, prod.availability_status,
        prod.image_url, prod.image_source_type,
      ]
    );
  }
  console.log(`   ✅ ${PRODUCTS.length} products processed.\n`);

  console.log("👤 Creating admin user …");
  const adminEmail = process.env.ADMIN_EMAIL || "admin@srinivasa.com";
  const adminPass  = process.env.ADMIN_PASSWORD || "admin123";
  const hash = await bcrypt.hash(adminPass, 10);

  await pool.execute(
    `INSERT IGNORE INTO users (id, name, email, phone, password_hash, role)
     VALUES (?, ?, ?, ?, ?, ?)`,
    ["admin-001", "Store Admin", adminEmail, "9666930275", hash, "admin"]
  );
  console.log(`   ✅ Admin: ${adminEmail}\n`);

  const mediaBase = path.resolve(__dirname, process.env.MEDIA_PATH || "./media");
  const dirs = [
    path.join(mediaBase, "products"),
    path.join(mediaBase, "prescriptions"),
  ];
  for (const dir of dirs) {
    fs.mkdirSync(dir, { recursive: true });
    console.log(`📁 Created: ${dir}`);
  }

  console.log("\n🎉 Database seeding complete! Start the server with: node index.js");
  await pool.end();
  process.exit(0);
}

main().catch((err) => {
  console.error("\n❌ Seeding failed:", err.message);
  process.exit(1);
});
